export const formatINR = (value) => {
  const amount = Number(value) || 0;
  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    maximumFractionDigits: 2,
  }).format(amount);
};

export const getProductImage = (item) => {
  if (item?.image_url) return item.image_url;
  // Deterministic placeholder derived from product name (no random photos).
  const title = item?.name || item?.product_name || item?.id || item?.sku || 'product';
  const text = String(title).slice(0, 48);
  return `https://placehold.co/600x450/png?text=${encodeURIComponent(text)}`;
};
